<?php
namespace App\Http\Controllers\Tenant;use App\Http\Controllers\Controller;use App\Models\{Payment,Plan};use App\Services\Billing\BillingService;use App\Support\CurrentWorkspace;use Illuminate\Http\Request;
class BillingController extends Controller{use Concerns;public function index(CurrentWorkspace $cw){$w=$this->ws($cw);return view('tenant.billing.index',['workspace'=>$w,'subscription'=>$w->subscription()->with('plan')->first(),'invoices'=>$w->invoices()->latest()->limit(5)->get(),'payments'=>$w->payments()->latest()->limit(5)->get()]);}public function plans(){return view('tenant.billing.plans',['plans'=>Plan::where('is_active',true)->where('is_public',true)->get()]);}public function payments(CurrentWorkspace $cw){return view('tenant.billing.payments.index',['payments'=>$this->ws($cw)->payments()->latest()->paginate(20)]);}public function manualPaymentRequest(Request $r,CurrentWorkspace $cw,BillingService $billing){$w=$this->ws($cw);$d=$r->validate(['invoice_id'=>'nullable|exists:invoices,id','amount'=>'required|numeric|min:0.01','transaction_reference'=>'nullable|string|max:255','verification_note'=>'nullable|string']);$invoice=isset($d['invoice_id'])?$w->invoices()->findOrFail($d['invoice_id']):null;Payment::create(['workspace_id'=>$w->id,'invoice_id'=>$invoice?->id,'subscription_id'=>$invoice?->subscription_id??$w->subscription?->id,'payment_number'=>$billing->generatePaymentNumber(),'gateway'=>'manual','status'=>'pending','currency'=>$invoice?->currency??$w->currency,'amount'=>$d['amount'],'transaction_reference'=>$d['transaction_reference']??null,'verification_note'=>$d['verification_note']??null]);return back()->with('status','Manual payment request submitted.');}}
